-- Crear una tarea
INSERT INTO tasks (title, user_id) VALUES ('Comprar comestibles', '...');

-- Leer todas las tareas de un usuario
SELECT * FROM tasks WHERE user_id = '...' ORDER BY created_at DESC;

-- Marcar una tarea como completa
UPDATE tasks SET is_complete = true WHERE id = '...' AND user_id = '...';

-- Eliminar una tarea
DELETE FROM tasks WHERE id = '...' AND user_id = '...';
